// Extract the Attio deal record id from whatever shape Attio (or a manual
// curl test) sends. Tolerant by design: accepts a flat { attio_deal_id },
// a { record: {...} } wrapper, or a raw Attio record object.
const j = $input.first().json;
const body = (j.body !== undefined && j.body !== null) ? j.body : j;
let dealId = body.attio_deal_id || body.attioDealId || body.deal_id || body.id;
if (dealId && typeof dealId === 'object') {
  dealId = dealId.record_id || dealId.id || null;
}
if (!dealId && body.record && body.record.id) {
  dealId = body.record.id.record_id || body.record.id;
}
if (!dealId || typeof dealId !== 'string') {
  throw new Error('Could not extract attio_deal_id from payload: ' + JSON.stringify(j).slice(0, 400));
}
// Trim — an Attio variable pill can resolve with stray surrounding whitespace,
// which would corrupt the GET URL. Strip it here so the rest of the chain is clean.
dealId = dealId.trim();
if (!dealId) {
  throw new Error('attio_deal_id was empty after trimming: ' + JSON.stringify(j).slice(0, 400));
}
return [{ json: { attio_deal_id: dealId } }];

// Pull email + name off the Person response; carry the deal id forward.
const person = $input.first().json;
const v = (person.data && person.data.values) || {};
const email = (v.email_addresses && v.email_addresses[0] && v.email_addresses[0].email_address) || '';
const nameObj = (v.name && v.name[0]) || {};
const dealId = $('Format Input').first().json.attio_deal_id;
if (!email) {
  throw new Error('Linked Person has no email address — cannot create a FirstPromoter promoter.');
}
return [{ json: {
  attio_deal_id: dealId,
  email: email,
  first_name: nameObj.first_name || '',
  last_name: nameObj.last_name || ''
}}];
